+import { DynamoDBToolboxError } from '~/errors/index.js'
+
+import type { ItemSchema, MapSchema } from '../types/index.js'
+
+/** Validate sibling-based requirements declared by map and item children. */
+export const checkRequiredIf = (schema: MapSchema | ItemSchema, path?: string): void => {
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    const requirements = attribute.props.requiredIf ?? []
+
+    if (attribute.props.key && requirements.length > 0) {
+      throw new DynamoDBToolboxError('schema.requiredIf.keyAttribute', {
+        message: `Invalid requiredIf requirement${path !== undefined ? ` at path '${path}'` : ''}: Key attribute '${attributeName}' cannot be conditionally required.`,
+        path,
+        payload: { attributeName }
+      })
+    }
+
+    for (const requirement of requirements) {
+      const controllingAttribute = schema.attributes[requirement.attributeName]
+      if (controllingAttribute === undefined) {
+        throw new DynamoDBToolboxError('schema.requiredIf.unknownAttribute', {
+          message: `Invalid requiredIf requirement${path !== undefined ? ` at path '${path}'` : ''}: '${requirement.attributeName}' is not a sibling attribute.`,
+          path,
+          payload: { attributeName, requirement }
+        })
+      }
+      if (requirement.attributeName === attributeName) {
+        throw new DynamoDBToolboxError('schema.requiredIf.selfReference', {
+          message: `Invalid requiredIf requirement${path !== undefined ? ` at path '${path}'` : ''}: '${attributeName}' cannot reference itself.`,
+          path,
+          payload: { attributeName, requirement }
+        })
+      }
+    }
+  }
+}
